#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        int min_diff = arr[1] - arr[0];
        for (int i = 1; i < N - 1; i++) {
            if (arr[i + 1] - arr[i] < min_diff) {
                min_diff = arr[i + 1] - arr[i];
            }
        }
        printf("%d\n", min_diff);
    }
    return 0;
}

